---
/* ContactForm — form with Cloudflare Turnstile spam protection and
   client-side fetch submission to /api/contact. */
const siteKey = import.meta.env.PUBLIC_TURNSTILE_SITE_KEY ?? '';
---

<form class="contact-form" novalidate>
  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-name">Name</label>
    <input
      class="contact-form__input"
      type="text"
      id="contact-name"
      name="name"
      required
      minlength="2"
      autocomplete="name"
      placeholder="Your name"
    />
    <span class="contact-form__error" data-field="name"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-email">Email</label>
    <input
      class="contact-form__input"
      type="email"
      id="contact-email"
      name="email"
      required
      autocomplete="email"
      placeholder="you@example.com"
    />
    <span class="contact-form__error" data-field="email"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-message">Message</label>
    <textarea
      class="contact-form__input contact-form__textarea"
      id="contact-message"
      name="message"
      required
      minlength="10"
      rows="5"
      placeholder="How can we help?"
    ></textarea>
    <span class="contact-form__error" data-field="message"></span>
  </div>

  <!-- Cloudflare Turnstile widget -->
  <div class="cf-turnstile" data-sitekey={siteKey} data-theme="light"></div>
  <span class="contact-form__error" data-field="turnstileToken"></span>

  <button class="contact-form__submit" type="submit">
    <span class="contact-form__submit-text">Send Message</span>
    <span class="contact-form__spinner" aria-hidden="true"></span>
  </button>

  <!-- General error banner -->
  <div class="contact-form__banner contact-form__banner--error" role="alert" hidden></div>

  <!-- Success message -->
  <div class="contact-form__banner contact-form__banner--success" role="status" hidden></div>
</form>

<!-- Turnstile script — loaded async to avoid blocking -->
<script is:inline src="https://challenges.cloudflare.com/turnstile/v0/api.js" async defer></script>

<script is:inline>
(function () {
  const form = document.querySelector('.contact-form');
  if (!form) return;

  const submitBtn = form.querySelector('.contact-form__submit');
  const submitText = form.querySelector('.contact-form__submit-text');
  const spinner = form.querySelector('.contact-form__spinner');
  const errorBanner = form.querySelector('.contact-form__banner--error');
  const successBanner = form.querySelector('.contact-form__banner--success');

  /* ---- Helpers ---- */

  function showFieldError(field, msg) {
    const el = form.querySelector('[data-field="' + field + '"]');
    if (el) {
      el.textContent = msg;
      el.hidden = false;
    }
    const input = form.querySelector('[name="' + field + '"]');
    if (input) input.classList.add('contact-form__input--error');
  }

  function clearErrors() {
    form.querySelectorAll('.contact-form__error').forEach(function (el) {
      el.textContent = '';
      el.hidden = true;
    });
    form.querySelectorAll('.contact-form__input--error').forEach(function (el) {
      el.classList.remove('contact-form__input--error');
    });
    errorBanner.hidden = true;
    errorBanner.textContent = '';
  }

  function setLoading(loading) {
    submitBtn.disabled = loading;
    submitText.textContent = loading ? 'Sending…' : 'Send Message';
    spinner.hidden = !loading;
  }

  /* ---- Client-side validation ---- */

  var EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  function validate() {
    var errors = [];
    var name = form.querySelector('[name="name"]').value.trim();
    var email = form.querySelector('[name="email"]').value.trim();
    var message = form.querySelector('[name="message"]').value.trim();

    if (name.length < 2) {
      errors.push({ field: 'name', message: 'Name is required (min 2 characters)' });
    }
    if (!EMAIL_RE.test(email)) {
      errors.push({ field: 'email', message: 'A valid email address is required' });
    }
    if (message.length < 10) {
      errors.push({ field: 'message', message: 'Message is required (min 10 characters)' });
    }
    return errors;
  }

  /* ---- Submission ---- */

  form.addEventListener('submit', async function (e) {
    e.preventDefault();
    clearErrors();
    successBanner.hidden = true;

    /* Client-side validation */
    var clientErrors = validate();
    if (clientErrors.length > 0) {
      clientErrors.forEach(function (err) { showFieldError(err.field, err.message); });
      return;
    }

    /* Get Turnstile token */
    var turnstileInput = form.querySelector('[name="cf-turnstile-response"]');
    var turnstileToken = turnstileInput ? turnstileInput.value : '';
    if (!turnstileToken) {
      showFieldError('turnstileToken', 'Please complete the captcha verification');
      return;
    }

    setLoading(true);

    var payload = {
      name: form.querySelector('[name="name"]').value.trim(),
      email: form.querySelector('[name="email"]').value.trim(),
      message: form.querySelector('[name="message"]').value.trim(),
      turnstileToken: turnstileToken,
    };

    try {
      var res = await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      var data = await res.json();

      if (!res.ok) {
        /* Field-level errors from server */
        if (data.fields && Array.isArray(data.fields)) {
          data.fields.forEach(function (err) { showFieldError(err.field, err.message); });
        }
        /* General error */
        errorBanner.textContent = data.error || 'Something went wrong. Please try again.';
        errorBanner.hidden = false;

        /* Reset Turnstile on failure so user can retry */
        if (typeof turnstile !== 'undefined') {
          turnstile.reset();
        }
        return;
      }

      /* Success */
      successBanner.textContent = data.message || 'Your message has been sent!';
      successBanner.hidden = false;
      form.reset();
      if (typeof turnstile !== 'undefined') {
        turnstile.reset();
      }
    } catch (err) {
      errorBanner.textContent = 'Network error. Please check your connection and try again.';
      errorBanner.hidden = false;
    } finally {
      setLoading(false);
    }
  });
})();
</script>

<style>
  .contact-form {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
    max-width: 36rem;
  }

  .contact-form__field {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .contact-form__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
  }

  .contact-form__input {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-4);
    transition: border-color var(--transition), box-shadow var(--transition);
  }

  .contact-form__input::placeholder {
    color: var(--color-stone);
  }

  .contact-form__input:focus {
    outline: none;
    border-color: var(--color-focus);
    box-shadow: 0 0 0 3px color-mix(in srgb, var(--color-focus) 25%, transparent);
  }

  .contact-form__input--error {
    border-color: var(--color-terracotta, #c0392b);
  }

  .contact-form__textarea {
    resize: vertical;
    min-height: 8rem;
  }

  .contact-form__error {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-terracotta, #c0392b);
    min-height: 0;
  }

  .contact-form__error:empty,
  .contact-form__error[hidden] {
    display: none;
  }

  .contact-form__submit {
    align-self: flex-start;
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    border: none;
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-8);
    cursor: pointer;
    transition: background-color var(--transition), box-shadow var(--transition), opacity var(--transition);
  }

  .contact-form__submit:hover:not(:disabled) {
    background-color: color-mix(in srgb, var(--color-terracotta) 85%, black);
  }

  .contact-form__submit:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .contact-form__submit:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }

  /* Spinner */
  .contact-form__spinner {
    display: none;
    width: 1em;
    height: 1em;
    border: 2px solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: contact-spin 0.6s linear infinite;
  }

  .contact-form__submit:disabled .contact-form__spinner {
    display: inline-block;
  }

  @keyframes contact-spin {
    to { transform: rotate(360deg); }
  }

  /* Banners */
  .contact-form__banner {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    padding: var(--space-3) var(--space-4);
    border-radius: var(--radius-sm);
  }

  .contact-form__banner[hidden] {
    display: none;
  }

  .contact-form__banner--error {
    color: #991b1b;
    background-color: #fef2f2;
    border: 1px solid #fecaca;
  }

  .contact-form__banner--success {
    color: #166534;
    background-color: #f0fdf4;
    border: 1px solid #bbf7d0;
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import Accordion from '../components/Accordion.astro';
import { getVisitPage, urlForImage, portableTextToHtml } from '../lib/sanity';

const title = 'Plan Your Visit | First Ithaca Chinese Christian Church';
const description =
  'Everything you need to know for your first Sunday with us — service times, directions, parking, and what to expect.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let visitPage: Awaited<ReturnType<typeof getVisitPage>> = null;

try {
  visitPage = await getVisitPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackSchedule = [
  {
    label: 'Sunday Gathering',
    time: '9:45 AM',
    description:
      'Worship service with singing, prayer, and a message from Scripture',
  },
  {
    label: 'Sunday School',
    time: '11:15 AM',
    description:
      'Age-specific classes for children, youth, and adults',
  },
];

const fallbackWhatToExpectHtml = `
<p>Whether it's your first time at church or you've been part of a community before, you're welcome here just as you are.</p>
<p><strong>Dress code:</strong> Come as you are — most people dress casually. You'll see everything from jeans to button-downs.</p>
<p><strong>What happens on Sunday:</strong> Our gathering includes worship through singing, prayer, Scripture reading, and a sermon. Services are primarily in English with occasional bilingual elements.</p>
<p><strong>Kids are welcome:</strong> Children are always welcome in the main service. We also offer age-appropriate Sunday School classes after the gathering.</p>
<p><strong>How long is the service?</strong> The Sunday gathering typically lasts about 75 minutes.</p>
`;

const fallbackTransportationHtml = `
<p><strong>Address:</strong> 429 Mitchell Street, Ithaca, NY 14850</p>
<p><strong>Parking:</strong> Free parking is available in our lot adjacent to the building. Street parking is also available on Mitchell Street and nearby side streets.</p>
<p><strong>Near Cornell:</strong> We're a short drive from Cornell University's campus. If you're a student without a car, we'd be happy to help arrange a ride — just ask!</p>
<p><strong>Public transit:</strong> TCAT bus routes serve the area. Check <a href="https://tcatbus.com">tcatbus.com</a> for schedules.</p>
`;

const fallbackFaqItems = [
  {
    question: 'What should I wear?',
    answer:
      `There's no dress code — come as you are. Most people dress casually.`,
  },
  {
    question: 'Are children welcome?',
    answer:
      'Absolutely! Children are welcome in the main service, and we offer Sunday School classes for different age groups after the gathering.',
  },
  {
    question: 'What language is the service in?',
    answer:
      'Our services are primarily in English with occasional bilingual (English/Chinese) elements. Everyone is welcome regardless of language background.',
  },
  {
    question: 'Is there parking available?',
    answer:
      'Yes — free parking is available in our lot next to the building, and street parking is available nearby.',
  },
  {
    question: 'How long is the service?',
    answer:
      'The Sunday gathering typically lasts about 75 minutes. Sunday School classes follow at 11:15 AM and run for about 45 minutes.',
  },
  {
    question: 'How can I get connected during the week?',
    answer:
      `We'd love to help you find community! After the service, stop by the welcome table to learn about small groups, Bible studies, and other ways to connect. You can also reach out through our contact page.`,
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = visitPage?.heroImage
  ? urlForImage(visitPage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = visitPage?.heroTitle || 'Plan Your Visit';
const heroSubtitle =
  visitPage?.heroSubtitle ||
  'Everything you need to know for your first Sunday with us';

const schedule =
  visitPage?.schedule && visitPage.schedule.length > 0
    ? visitPage.schedule
    : fallbackSchedule;

const whatToExpectHtml =
  visitPage?.whatToExpect && visitPage.whatToExpect.length > 0
    ? portableTextToHtml(visitPage.whatToExpect)
    : fallbackWhatToExpectHtml;

const transportationHtml =
  visitPage?.transportation && visitPage.transportation.length > 0
    ? portableTextToHtml(visitPage.transportation)
    : fallbackTransportationHtml;

const faqItems =
  visitPage?.faqItems && visitPage.faqItems.length > 0
    ? visitPage.faqItems
    : fallbackFaqItems;

// Map FAQ items to Accordion's expected shape
const accordionItems = faqItems.map((item) => ({
  title: item.question,
  content: item.answer,
}));
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      backgroundImage={heroImage}
    />

    <!-- Schedule -->
    <section class="schedule" aria-label="Sunday Schedule">
      <div class="schedule__inner">
        <h2 class="section-heading">Sunday Schedule</h2>
        <div class="schedule__grid">
          {schedule.map((item) => (
            <div class="schedule__card">
              <span class="schedule__time">{item.time}</span>
              <h3 class="schedule__label">{item.label}</h3>
              {item.description && (
                <p class="schedule__desc">{item.description}</p>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>

    <!-- What to Expect -->
    <section class="expect" aria-label="What to Expect">
      <div class="expect__inner">
        <h2 class="section-heading">What to Expect</h2>
        <div class="expect__body" set:html={whatToExpectHtml} />
      </div>
    </section>

    <!-- Transportation & Directions -->
    <section class="directions" aria-label="Transportation and Directions">
      <div class="directions__inner">
        <h2 class="section-heading">Getting Here</h2>
        <div class="directions__columns">
          <div class="directions__body" set:html={transportationHtml} />
          <div class="directions__map">
            <iframe
              title="Church location on Google Maps"
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2942.8!2d-76.5005!3d42.4440!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2z429+Mitchell+Street%2C+Ithaca%2C+NY+14850!5e0!3m2!1sen!2sus!4v1"
              width="100%"
              height="300"
              style="border:0; border-radius: var(--radius-md);"
              allowfullscreen=""
              loading="lazy"
              referrerpolicy="no-referrer-when-downgrade"
            ></iframe>
          </div>
        </div>
      </div>
    </section>

    <!-- FAQ -->
    <section class="faq" aria-label="Frequently Asked Questions">
      <div class="faq__inner">
        <h2 class="section-heading">Frequently Asked Questions</h2>
        <Accordion items={accordionItems} />
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  /* ---------- Shared ---------- */
  .section-heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-10);
  }

  /* ---------- Schedule ---------- */
  .schedule {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .schedule__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .schedule__grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));
    gap: var(--space-8);
  }

  .schedule__card {
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
    padding: var(--space-8) var(--space-6);
    text-align: center;
  }

  .schedule__time {
    display: block;
    font-family: var(--font-heading);
    font-size: var(--text-2xl);
    font-weight: 700;
    color: var(--color-terracotta);
    margin-block-end: var(--space-2);
  }

  .schedule__label {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    color: var(--color-ink);
    margin-block-end: var(--space-3);
  }

  .schedule__desc {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  /* ---------- What to Expect ---------- */
  .expect {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .expect__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .expect__body {
    max-width: 48rem;
    margin-inline: auto;
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .expect__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .expect__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .expect__body :global(strong) {
    color: var(--color-ink);
  }

  /* ---------- Directions ---------- */
  .directions {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .directions__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .directions__columns {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-10);
    align-items: start;
  }

  .directions__body {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .directions__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .directions__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .directions__body :global(strong) {
    color: var(--color-ink);
  }

  .directions__body :global(a) {
    color: var(--color-terracotta);
    text-decoration: underline;
  }

  .directions__map {
    border-radius: var(--radius-md);
    overflow: hidden;
  }

  .directions__map iframe {
    display: block;
  }

  /* ---------- FAQ ---------- */
  .faq {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .faq__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 768px) {
    .section-heading {
      font-size: var(--text-2xl);
    }

    .directions__columns {
      grid-template-columns: 1fr;
    }

    .schedule__grid {
      grid-template-columns: 1fr;
    }
  }
</style>

